async (params, browser) => {
  // Search MyFitnessPal food database
  await browser.open(`https://www.myfitnesspal.com/food/search?search=${params.query}`)

  // Wait for results
  await browser.waitForSelector('.food-description, [class*="FoodItem"], li, .search-results', 15000)

  // Let results render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('.food-description, [class*="FoodItem"], li.food-item, .search-results li').forEach((el,i) => { if(i>=15) return; const titleEl = el.querySelector('a, .food-name, [class*="name"]'); const calEl = el.querySelector('.food-calories, [class*="calories"], .nutritional-column'); results.push({ name: titleEl?titleEl.textContent.trim():'', url: titleEl?.href||'', calories: calEl?calEl.textContent.trim():'' }); }); return { query: '' + params.query + '', results }`)

  return search_results
}
